La estructura try-except
Python usa try (intentar) y except (excepto) para manejar errores:
# Estructura básica
try:
    # Código que podría fallar
    resultado = 10 / 0
except ZeroDivisionError:
    # Qué hacer si ocurre este error específico
    print("⚠️ No se puede dividir por cero")

Ejemplo práctico: Lectura de sensor
def leer_sensor_distancia():
    """
    Simula la lectura de un sensor de distancia.
    En un caso real, esto se conectaría al hardware.
    """
    import random

    # Simulamos diferentes escenarios
    escenario = random.choice(["normal", "error_conexion", "valor_invalido"])

    if escenario == "normal":
        return random.uniform(5, 100)  # Distancia normal
    elif escenario == "error_conexion":
        raise ConnectionError("Sensor no responde")
    else:
        raise ValueError("Lectura fuera de rango válido")

# Manejo robusto de la lectura
for intento in range(3):
    try:
        distancia = leer_sensor_distancia()
        print(f"Distancia medida: {distancia:.1f} cm")
        break  # Salir del bucle si todo sale bien

    except ConnectionError as e:
        print(f"⚠️ Error de conexión (intento {intento + 1}/3): {e}")
        if intento &lt; 2:
            print("   Reintentando en 1 segundo...")
        else:
            print("   ❌ Sensor no disponible después de 3 intentos")

    except ValueError as e:
        print(f"⚠️ Valor inválido: {e}")
        print("   Saltando esta lectura...")

    except Exception as e:
        # Captura cualquier otro error no previsto
        print(f"❌ Error inesperado: {type(e).__name__}: {e}")
        break

Ejemplo integrado: Sistema de telemetría
Veamos cómo usar listas y diccionarios juntos en un sistema de robótica:
# Definición de un robot
robot = {
    "nombre": "Explorador",
    "sensores": {
        "color": {"valor": "rojo", "unidad": "color"},
        "distancia": {"valor": 25.5, "unidad": "cm"},
        "fuerza": {"valor": 0, "unidad": "N"}
    },
    "motores": {
        "izquierdo": {"velocidad": 0, "posicion": 0},
        "derecho": {"velocidad": 0, "posicion": 0}
    }
}

def actualizar_sensor(nombre_sensor, nuevo_valor):
    """Actualiza el valor de un sensor."""
    if nombre_sensor in robot["sensores"]:
        robot["sensores"][nombre_sensor]["valor"] = nuevo_valor
        print(f"✅ Sensor '{nombre_sensor}' actualizado a {nuevo_valor}")
    else:
        print(f"⚠️ Sensor '{nombre_sensor}' no encontrado")

def obtener_telemetria():
    """Recolecta todos los datos de telemetría."""
    print("\n=== TELEMETRÍA DEL ROBOT ===")
    print(f"Robot: {robot['nombre']}")
    print("\n📡 Sensores:")
    for nombre, datos in robot["sensores"].items():
        print(f"  {nombre}: {datos['valor']} {datos['unidad']}")
    print("\n🔧 Motores:")
    for nombre, datos in robot["motores"].items():
        print(f"  {nombre}: vel={datos['velocidad']}, pos={datos['posicion']}")

# Simulación de operación
actualizar_sensor("distancia", 15.3)
actualizar_sensor("fuerza", 5.2)
obtener_telemetria()

